def filter_by_bin(q, "All") do
  {:ok, q}
end
def filter_by_bin(q, bins) when byte_size(bins) > 0 do
  bins = String.split(bins, ",")
  {:ok, from(acc in q, where: acc.bin in ^bins)}
end
def filter_by_bin(q, _bins) do
  {:ok, q}
end

def filter_by_in_next_two(q, "true") do
  {:ok, from(acc in q, where: acc.in_next_two)}
end
def filter_by_in_next_two(q, "false") do
  {:ok, from(acc in q, where: not acc.in_next_two)}
end
def filter_by_in_next_two(q, _value) do
  {:ok, q}
end

def filter_by_timeframe(q, chart_range, _date, start_date, end_date)
    when (chart_range == "Daily" or chart_range == "By Station") and is_binary(start_date) and
           is_binary(end_date) do
  case {Date.from_iso8601(start_date), Date.from_iso8601(end_date)} do
    {{:ok, d1}, {:ok, d2}} ->
      case Timex.diff(d2, d1, :days) do
        n when n < 0 -> {:error, "Start date is after end date"}
        n when n > 35 -> {:error, "Dates can't be more than 5 weeks apart"}
        _ -> {:ok, from(acc in q, where: acc.service_date >= ^d1 and acc.service_date <= ^d2)}
      end

    _ ->
      {:error, "Can't parse start or end date."}
  end
end
def filter_by_timeframe(q, "Hourly", date, _daily_start, _daily_end) when is_binary(date) do
  case Date.from_iso8601(date) do
    {:ok, d} -> {:ok, from(acc in q, where: acc.service_date == ^d)}
    _ -> {:error, "Can't parse service date."}
  end
end
def filter_by_timeframe(_q, "Hourly", _, _, _) do
  {:error, "No service date given."}
end
def filter_by_timeframe(_q, "Daily", _, _, _) do
  {:error, "No start or end date given."}
end
def filter_by_timeframe(_q, "By Station", _, _, _) do
  {:error, "No start or end date given."}
end

